namespace sv_539bd11ebbe04421bc0056080244478c.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service (per-circuit in Blazor Server) that holds the currently
/// selected warehouse and notifies subscribers when it changes.
/// </summary>
public class WarehouseStateService
{
    private static readonly List<WarehouseInfo> _availableWarehouses =
    [
        new() { Id = "WH-001", Name = "Warehouse A – Main Distribution" },
        new() { Id = "WH-002", Name = "Warehouse B – East Coast" },
        new() { Id = "WH-003", Name = "Warehouse C – West Coast" },
        new() { Id = "WH-004", Name = "Warehouse D – Returns Processing" },
    ];

    public IReadOnlyList<WarehouseInfo> AvailableWarehouses => _availableWarehouses;

    public string CurrentWarehouseId { get; private set; } = _availableWarehouses[0].Id;

    public string CurrentWarehouseName =>
        _availableWarehouses.First(w => w.Id == CurrentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (warehouseId == CurrentWarehouseId)
            return;

        if (_availableWarehouses.All(w => w.Id != warehouseId))
            throw new ArgumentException($"Unknown warehouse: {warehouseId}");

        CurrentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_539bd11ebbe04421bc0056080244478c.Services;

/// <summary>
/// Scoped service (per-circuit) that provides low-stock alert counts and
/// broadcasts changes so every subscribed component updates together.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int LastKnownCount { get; private set; }

    /// <summary>
    /// Fired whenever a new alert count is available. All subscribed
    /// components (sidebar badge, dashboard panel, etc.) receive this
    /// regardless of which component triggered the poll.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning the number of items
    /// below minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate varying latency and results per warehouse
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches a fresh count and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LastKnownCount = await GetLowStockCountAsync(warehouseId);
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }
}

