@page "/dashboard"
@using sv_539bd11ebbe04421bc0056080244478c.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(_alertCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(_alertCount > 0 ? "text-danger" : "text-success")">
                    @_alertCount
                </p>
                <p class="card-text text-muted">
                    Items below minimum level
                </p>
                <small class="text-muted">
                    @if (_lastRefresh.HasValue)
                    {
                        <span>Last checked: @_lastRefresh.Value.ToString("HH:mm:ss")</span>
                    }
                    else
                    {
                        <span>Waiting for first poll…</span>
                    }
                </small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6">
                    @if (_isPolling)
                    {
                        <span class="badge bg-success">Active</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Stopped</span>
                    }
                </p>
                <p class="card-text text-muted">Refreshes every 10 seconds</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Site</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouseId</p>
                <p class="card-text text-muted">
                    Change warehouse in the top bar
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _alertCount;
    private DateTime? _lastRefresh;
    private bool _isPolling;
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            StartPolling();
        }
        return Task.CompletedTask;
    }

    private void OnWarehouseChanged()
    {
        // Restart polling against the newly selected warehouse
        StopPolling();
        StartPolling();
        InvokeAsync(StateHasChanged);
    }

    private async Task OnAlertCountChanged()
    {
        _alertCount = AlertService.LastKnownCount;
        _lastRefresh = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        // Immediate first fetch
        await RefreshAlerts();

        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await RefreshAlerts();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when polling is stopped
        }
    }

    private async Task RefreshAlerts()
    {
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
        // OnAlertCountChanged handler updates _alertCount and _lastRefresh
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _isPolling = false;
    }

    public void Dispose()
    {
        StopPolling();
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

